using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 changed the default StatusStrip RenderMode from System to
        // Professional. Set explicitly to preserve .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }

    [Editor(typeof(DisplayNameEditor), typeof(UITypeEditor))]
    public string DisplayName { get; set; }

    public int MaxItems { get; set; }
}

internal class DisplayNameEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider? provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null)
            return value;

        using var control = BuildListBox(value);

        // .NET 9 throws ArgumentNullException when null is passed to
        // DropDownControl. Guard against null before calling.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = control.SelectedItem;
        }

        return value;
    }

    private static ListBox? BuildListBox(object? currentValue)
    {
        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
        if (currentValue is string s)
            listBox.SelectedItem = s;
        return listBox.Items.Count > 0 ? listBox : null;
    }
}

